import React from 'react';

function About() {
  return (
    <section id="about" style={{ height: '100vh', padding: '50px', backgroundColor: '#e4e4e4', position: 'relative' }}>
      <div style={{ textAlign: 'center', marginBottom: '40px' }}>
        <h1>About Me</h1>  {/* Centered at the top */}
      </div>
      <div style={{ textAlign: 'center' }}>
        <p>This is the about section of my portfolio where I talk about my background.</p>
      </div>
    </section>
  );
}

export default About;
